scwin.onUdcCompleted = function () {
  $c.gus.cfDisableObjects($p, [ed_clntNo, txt_clntNm, ed_commCd, txt_commNm, txt_rmk]);
  ed_wrkStDt.setValue(scwin.pastYm + "01");
  ed_wrkEndDt.setValue(scwin.nowDt);
};

//-------------------------------------------------------------------------
// 조회 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (!(await $c.gus.cfValidate($p, [ed_wrkStDt, ed_wrkEndDt, ed_cvsslMgntNo]))) {
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_wrkStDt.getValue(), ed_wrkEndDt.getValue())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자가 종료일자 이전이어야 합니다.;
    ed_wrkStDt.focus();
    return;
  }
  $c.sbm.execute($p, sbm_search);
};

//-------------------------------------------------------------------------
// 일자별 보관료 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = async function () {
  ds_condition2.set("stockMgntNo", ds_result.getCellData(ds_result.getRowPosition(), "stockMgntNo"));
  ds_condition2.set("dcsnClsCd", scwin.lc_dcsnClsCd);
  $c.sbm.execute($p, sbm_search2);
};

//-------------------------------------------------------------------------
// 재고정보 저장(보관료 상태 변경)
//-------------------------------------------------------------------------	  
scwin.f_save = async function () {
  if (!(await $c.gus.cfValidate($p, [ds_result]))) {
    return;
  }
  var stsCd;
  var edDt;
  var RowStatus;
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    $c.sbm.execute($p, sbm_save);
  }
};

//-------------------------------------------------------------------------
// 일자별 보관료 저장
//-------------------------------------------------------------------------	  
scwin.f_save2 = async function () {
  if (ds_master.getModifiedIndex().length > 0) {
    if (!(await $c.gus.cfValidate($p, [ds_detail]))) {
      return;
    }
    for (var i = 0; i < ds_detail.getTotalRow(); i++) {
      var RowStatus = ds_detail.getRowStatus(i);
      if (RowStatus == "D") {
        var stsCd = ds_detail.getCellData(i, "dcsnClsCd"); // 상태코드
        if (stsCd != "") {
          // 진행, 제외
          // gr_detail.setFocusedCell(i, 0);
          ds_detail.setRowPosition(i);
          await $c.gus.cfAlertMsg($p, i + "행 상태가 진행중인 경우 보관료 내역을 변경할 수없습니다.");
          return;
        }
      }
    }
    if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
      $c.sbm.execute($p, sbm_save2);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["일자별 보관료 내역"]); // @은(는) 변경된 사항이 없습니다			
  }
};

