  var commNm = ds_result.getCellData(ds_result.getRowPosition(), "commNm");
  var clntNm = ds_result.getCellData(ds_result.getRowPosition(), "clntNm");
  var bulkHandOverClntNo = ds_result.getCellData(ds_result.getRowPosition(), "bulkHandOverClntNo");
  var bulkHandOverClntNm = ds_result.getCellData(ds_result.getRowPosition(), "bulkHandOverClntNm");
