scwin.gr_result_oncellclick = async function (rowIndex, columnIndex, columnId) {
  if (rowIndex >= 0) {
    // txt_rmk.setValue(ds_result.getCellData(rowIndex, "rmk"));

    var clntNm = ds_result.getCellData(rowIndex, "clntNm");
    var oldChk = ds_result.getCellData(rowIndex, "chk");
    if (columnId == "run") {
      await $c.win.alert($p, clntNm + '의 엑셀 실행');
      await scwin.f_Retrieve2();
      await scwin.f_runExcel();
    } else {
      await scwin.f_Retrieve2();
    }
  }
};

